insert into assinaturas (nome, titulo, mensagem, aprovado) values
('Aristides Camargo Neto', 'Advogado, entusiasta de abaixo-assinados', 'Assinei a carta com a mesma convicção com que assino boletos: solenemente e sem alterar o resultado.', true),
('Maria Clotilde Bandeira', 'Professora aposentada, Recife/PE', 'Peço desculpas. Na hora pareceu que eu estava salvando a República. Era só o meu momento de protagonismo no PDF.', true),
('Ubirajara Fontes', 'Bacharel em Direito e em arrependimento', 'Reconheci firma no cartório para dar peso jurídico à minha assinatura. O peso era o do papel: 75 g/m².', true),
('Dona Zélia', 'Fundadora do grupo ''Vizinhas pela Democracia''', 'Compartilhei a carta em três grupos de zap. A democracia não percebeu, mas minha cunhada brigou comigo mesmo assim.', true),
('Epaminondas Silveira', 'Colecionador de manifestos históricos', 'Já assinei catorze cartas históricas. Nenhuma funcionou, mas esta foi a que menos funcionou com mais pompa.', true),
('Valquíria Prado', 'Publicitária, São Paulo/SP', 'Fiz até um post com fundo preto e tipografia serifada. Engajou bastante. A democracia, nem tanto.', true),
('Anísio Bittencourt', 'Largo de São Francisco, turma de 1987', 'Assinei entre a aula de latim jurídico e o cafezinho. Foi o intervalo mais cívico da minha vida, e o mais inútil.', true),
('Gertrudes Malaquias', 'Tabeliã emocionada', 'Reconheci trezentas e quarenta firmas naquele mês. Peço desculpas em nome do cartório e do meu carimbo.', true),
('Percival Drummond', 'Poeta bissexto', 'Assinei em versos alexandrinos. A métrica estava perfeita; a eficácia, nem tanto.', true),
('Jandira Vasconcelos', 'Historiadora', 'Como historiadora, eu devia saber que manifesto de agosto raramente muda setembro. Peço desculpas pela amnésia profissional.', true),
('Teodoro Lins e Silva', 'Jurista de sofá', 'Citei Rui Barbosa no churrasco de domingo e assinei na segunda-feira. Rui não retornou minhas ligações.', true),
('Ofélia Sant''Anna', 'Soprano do coral ''Vozes da Constituição''', 'Cantamos o hino após a leitura solene da carta. Desafinei no ''ouviram do Ipiranga'', e sinto que a democracia ouviu tudo.', true),
('Nepomuceno Sales', 'Empresário do ramo de molduras', 'Confesso o conflito de interesses: vendi duzentas molduras para exemplares da carta. Peço desculpas e parcelo em três vezes.', true),
('Bartolomeu Quintanilha', 'Estudante de Direito, 9º período', 'Assinei achando que valia horas complementares. Não valeu nem isso.', true),
('Dilermando Rocha', 'Engenheiro civil, otimista estrutural', 'Calculei que a carta suportaria o peso das instituições. Errei o coeficiente de segurança.', true),
('Filomena Castelo Branco', 'Bordadeira, Campina Grande/PB', 'Bordei o trecho final num pano de prato. O pano de prato segue mais útil que a carta.', true),
('Astrogildo Meireles', 'Sommelier de crises institucionais', 'Harmonizei minha assinatura com um espumante nacional. A ressaca veio, e não foi do espumante.', true),
('Cândida Prudente', 'Dona de casa e de opiniões', 'Assinei pelo casal. Meu marido também pede desculpas, mas por procuração.', true),
('Belarmino Fagundes', 'Taxista e cientista político de trânsito', 'Recolhi doze assinaturas no banco de trás e cobrei bandeira dois pela militância. Devolvo o troco em arrependimento.', true),
('Segismundo Torres', 'Signatário reincidente', 'Assino esta retratação já com receio de, em 2028, ter de assinar a retratação da retratação.', true);
